#!/bin/bash
# Fixes "connection not open" — installs HTTP migrate and patches package.json.
# Run from project root: bash scripts/install-http-migrate.sh
set -e
ROOT="$(cd "$(dirname "$0")/.." && pwd)"
cd "$ROOT"

mkdir -p scripts
base64 -d << 'B64' > scripts/migrate-authority-http.js

B64
chmod +x scripts/migrate-authority-http.js

if grep -q "migrate-authority-http.js" package.json; then
  echo "package.json already patched"
else
  sed -i.bak 's|truffle migrate --reset hard --network authority --f 2|truffle compile \&\& node scripts/migrate-authority-http.js|' package.json
  rm -f package.json.bak
  echo "Patched package.json"
fi

echo ""
grep migrate-contracts-authority package.json
echo ""
echo "Done. Run: yarn migrate-contracts-authority"
